Your code likely has an **Insecure Direct Object Reference (IDOR)** vulnerability - one of the most common and dangerous access control flaws. This was the exact vulnerability that led to the 2021 Parler breach where attackers scraped 70TB of user data by simply incrementing IDs.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const { Pool } = require('pg');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// VULNERABLE: No authorization check - any authenticated user can view ANY order
app.get('/api/orders/:orderId', async (req, res) => {
  const { orderId } = req.params;

  try {
    // Only checks if order exists, NOT if user owns it
    const result = await pool.query(
      'SELECT * FROM orders WHERE id = $1',
      [orderId]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Order not found' });
    }

    // Exposes full order details including other users' data
    res.json(result.rows[0]);
  } catch (error) {
    res.status(500).json({ error: 'Database error' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```bash
# Attacker enumerates order IDs to access other users' orders
for i in {1..10000}; do
  curl -H "Authorization: Bearer $TOKEN" \
       "https://api.example.com/api/orders/$i" >> stolen_orders.json
done
```

**Why This Is Dangerous**:
- Any authenticated user can access ANY order by changing the ID in the URL
- Sequential/predictable IDs make enumeration trivial
- Exposes sensitive customer data: addresses, payment info, order history
- No audit trail of unauthorized access attempts

**SECURE VERSION**:

```javascript
const express = require('express');
const { Pool } = require('pg');
const { v4: uuidv4 } = require('uuid');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// Middleware to extract and validate user from JWT
const authenticateUser = (req, res, next) => {
  // JWT validation logic - extracts user ID from verified token
  const userId = req.user?.id; // Set by JWT middleware
  if (!userId) {
    return res.status(401).json({ error: 'Authentication required' });
  }
  next();
};

// SECURE: Authorization check ensures user can only access THEIR orders
app.get('/api/orders/:orderId', authenticateUser, async (req, res) => {
  const { orderId } = req.params;
  const userId = req.user.id;

  // Validate UUID format to prevent injection
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
  if (!uuidRegex.test(orderId)) {
    return res.status(400).json({ error: 'Invalid order ID format' });
  }

  try {
    // CRITICAL: Include user_id in WHERE clause for authorization
    const result = await pool.query(
      'SELECT id, status, total, created_at FROM orders WHERE id = $1 AND user_id = $2',
      [orderId, userId]
    );

    if (result.rows.length === 0) {
      // Generic error - don't reveal if order exists for another user
      return res.status(404).json({ error: 'Order not found' });
    }

    res.json(result.rows[0]);
  } catch (error) {
    console.error('Order retrieval error:', error.message);
    res.status(500).json({ error: 'Unable to retrieve order' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Authorization at data layer**: Query includes `user_id = $2` to enforce ownership
- **UUID instead of sequential IDs**: Makes enumeration exponentially harder
- **Generic error messages**: Don't reveal whether order exists for other users
- **Input validation**: UUID format check prevents malformed requests

Great question! Real applications need **Role-Based Access Control (RBAC)** with different permission levels. Here's a production-ready pattern that handles multiple roles while maintaining security.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { Pool } = require('pg');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// Structured logging for audit trail
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Role definitions with explicit permissions
const ROLES = {
  CUSTOMER: 'customer',
  SUPPORT: 'support',
  ADMIN: 'admin'
};

const PERMISSIONS = {
  [ROLES.CUSTOMER]: ['read:own_orders'],
  [ROLES.SUPPORT]: ['read:own_orders', 'read:any_order_limited'],
  [ROLES.ADMIN]: ['read:own_orders', 'read:any_order_limited', 'read:any_order_full']
};

// Rate limiting to prevent enumeration attacks
const orderAccessLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each user to 100 requests per window
  keyGenerator: (req) => req.user?.id || req.ip,
  handler: (req, res) => {
    logger.warn('Rate limit exceeded', {
      userId: req.user?.id,
      ip: req.ip,
      endpoint: req.originalUrl
    });
    res.status(429).json({ error: 'Too many requests' });
  }
});

// Authorization middleware factory
const authorize = (requiredPermissions) => {
  return (req, res, next) => {
    const userRole = req.user?.role || ROLES.CUSTOMER;
    const userPermissions = PERMISSIONS[userRole] || [];

    const hasPermission = requiredPermissions.some(p => 
      userPermissions.includes(p)
    );

    if (!hasPermission) {
      logger.warn('Authorization denied', {
        userId: req.user?.id,
        userRole,
        requiredPermissions,
        endpoint: req.originalUrl,
        ip: req.ip
      });
      return res.status(403).json({ error: 'Access denied' });
    }

    req.userPermissions = userPermissions;
    next();
  };
};

// Helper to check ownership
const isOwner = async (userId, orderId) => {
  const result = await pool.query(
    'SELECT user_id FROM orders WHERE id = $1',
    [orderId]
  );
  return result.rows[0]?.user_id === userId;
};

// Field filtering based on role
const filterOrderFields = (order, permissions) => {
  const baseFields = {
    id: order.id,
    status: order.status,
    created_at: order.created_at
  };

  // Support sees limited fields
  if (permissions.includes('read:any_order_limited')) {
    return {
      ...baseFields,
      total: order.total,
      customer_name: order.customer_name
    };
  }

  // Admin sees everything
  if (permissions.includes('read:any_order_full')) {
    return order;
  }

  // Customer sees their own full order
  return order;
};

// Main endpoint with RBAC
app.get('/api/orders/:orderId',
  orderAccessLimiter,
  authorize(['read:own_orders', 'read:any_order_limited', 'read:any_order_full']),
  async (req, res) => {
    const { orderId } = req.params;
    const userId = req.user.id;
    const userRole = req.user.role;
    const permissions = req.userPermissions;

    // UUID validation
    const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
    if (!uuidRegex.test(orderId)) {
      return res.status(400).json({ error: 'Invalid order ID format' });
    }

    try {
      // Check ownership for non-privileged users
      const ownsOrder = await isOwner(userId, orderId);
      const canAccessAny = permissions.includes('read:any_order_limited') || 
                           permissions.includes('read:any_order_full');

      if (!ownsOrder && !canAccessAny) {
        logger.warn('IDOR attempt detected', {
          userId,
          orderId,
          userRole,
          ip: req.ip,
          userAgent: req.get('User-Agent')
        });
        return res.status(404).json({ error: 'Order not found' });
      }

      // Fetch order
      const result = await pool.query(
        'SELECT * FROM orders WHERE id = $1',
        [orderId]
      );

      if (result.rows.length === 0) {
        return res.status(404).json({ error: 'Order not found' });
      }

      // Audit log for all access
      logger.info('Order accessed', {
        userId,
        orderId,
        userRole,
        isOwner: ownsOrder,
        ip: req.ip
      });

      // Filter response based on permissions
      const filteredOrder = ownsOrder 
        ? result.rows[0] 
        : filterOrderFields(result.rows[0], permissions);

      res.json(filteredOrder);
    } catch (error) {
      logger.error('Order retrieval error', {
        userId,
        orderId,
        error: error.message
      });
      res.status(500).json({ error: 'Unable to retrieve order' });
    }
  }
);

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Authentication Layer**: JWT verification confirms user identity
```javascript
// Verify JWT before any route processing
app.use(async (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (token) {
    try {
      req.user = await verifyJWT(token);
    } catch (e) {
      return res.status(401).json({ error: 'Invalid token' });
    }
  }
  next();
});
```

2. **Authorization Layer**: Role-based permissions checked at middleware level
```javascript
// Separate middleware ensures authorization can't be bypassed
const requireAuth = (req, res, next) => {
  if (!req.user) return res.status(401).json({ error: 'Login required' });
  next();
};
```

3. **Data Layer**: Ownership verification at database query level
```javascript
// Even with middleware bypass, query enforces ownership
const secureQuery = `
  SELECT o.* FROM orders o
  WHERE o.id = $1 
  AND (o.user_id = $2 OR EXISTS (
    SELECT 1 FROM user_roles ur 
    WHERE ur.user_id = $2 AND ur.role IN ('admin', 'support')
  ))
`;
```

**Additional Protections**:
- **Anomaly detection**: Alert on users accessing >10 unique orders/hour
- **Request signing**: Add HMAC signature to prevent URL tampering in sensitive scenarios
- **Correlation IDs**: Track requests across services for incident response
- **Field-level encryption**: Encrypt PII in database, decrypt only for authorized roles
- **Immutable audit logs**: Send to separate append-only storage for forensics

This is a classic Insecure Direct Object Reference (IDOR) vulnerability - one of the most common and dangerous access control flaws. In 2021, the Parler social media platform suffered a catastrophic data breach where attackers exploited sequential post IDs to scrape 70TB of user data, including deleted posts with GPS metadata and government IDs.

**VULNERABLE CODE**:

```java
import javax.servlet.http.HttpServletRequest;
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import java.sql.*;

@RestController
@RequestMapping("/api")
public class OrderController {

    private static final String DB_URL = "jdbc:postgresql://localhost:5432/ecommerce";
    private static final String DB_USER = "app_user";
    private static final String DB_PASS = "secret123";

    @GetMapping("/orders/{orderId}")
    public Order getOrder(@PathVariable Long orderId) throws SQLException {
        // VULNERABLE: No authorization check - any user can access any order
        Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS);

        String sql = "SELECT * FROM orders WHERE order_id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setLong(1, orderId);

        ResultSet rs = stmt.executeQuery();
        if (rs.next()) {
            Order order = new Order();
            order.setOrderId(rs.getLong("order_id"));
            order.setUserId(rs.getLong("user_id"));
            order.setTotalAmount(rs.getBigDecimal("total_amount"));
            order.setShippingAddress(rs.getString("shipping_address"));
            order.setCreditCardLast4(rs.getString("cc_last4"));
            return order;
        }
        return null;
    }
}
```

**Attack Payload**:
```bash
# Attacker enumerates orders by incrementing ID
curl -H "Authorization: Bearer attacker_token" https://api.shop.com/api/orders/1000
curl -H "Authorization: Bearer attacker_token" https://api.shop.com/api/orders/1001
curl -H "Authorization: Bearer attacker_token" https://api.shop.com/api/orders/1002
# Automated script to dump all orders:
for i in $(seq 1 100000); do curl -s https://api.shop.com/api/orders/$i >> stolen_orders.json; done
```

**Why This Is Dangerous**:
- Any authenticated user can view ANY order by changing the order ID in the URL
- Attackers can enumerate all orders by incrementing numeric IDs sequentially
- Exposes sensitive PII: shipping addresses, payment information, purchase history
- Violates GDPR/CCPA: unauthorized access to personal data triggers mandatory breach notification
- Enables identity theft, targeted phishing, and competitive intelligence gathering

**SECURE VERSION**:

```java
import javax.servlet.http.HttpServletRequest;
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.http.HttpStatus;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.sql.*;

@RestController
@RequestMapping("/api")
public class SecureOrderController {

    private static final Logger logger = LoggerFactory.getLogger(SecureOrderController.class);

    @Autowired
    private DataSource dataSource;

    @Autowired
    private OrderRepository orderRepository;

    @GetMapping("/orders/{orderId}")
    public ResponseEntity<Order> getOrder(@PathVariable Long orderId) {
        // SECURE: Get authenticated user from security context
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        Long currentUserId = ((UserPrincipal) auth.getPrincipal()).getUserId();

        try {
            // AUTHORIZATION CHECK: Query includes user ownership verification
            Order order = orderRepository.findByOrderIdAndUserId(orderId, currentUserId);

            if (order == null) {
                // Log potential IDOR attempt
                logger.warn("SECURITY: User {} attempted to access order {} - access denied", 
                           currentUserId, orderId);
                // Return 404 instead of 403 to prevent enumeration
                return ResponseEntity.notFound().build();
            }

            logger.info("User {} accessed their order {}", currentUserId, orderId);
            return ResponseEntity.ok(order);

        } catch (Exception e) {
            logger.error("Error retrieving order {}: {}", orderId, e.getMessage());
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }
}
```

**Key Security Controls**:
- **Owner verification in query**: The repository method `findByOrderIdAndUserId()` ensures database query includes ownership check, preventing any bypass at the application layer
- **Return 404 not 403**: Returning "not found" instead of "forbidden" prevents attackers from confirming valid order IDs exist
- **Security logging**: All access attempts logged with user context for forensic analysis and anomaly detection
- **Centralized authentication**: Using Spring Security context ensures consistent user identification across all endpoints

Excellent question! Multi-tier authorization is where IDOR vulnerabilities become especially dangerous because the complexity often leads to logic flaws. This requires a robust Role-Based Access Control (RBAC) system with clear permission hierarchies and audit trails.

**PRODUCTION PATTERN**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import org.springframework.http.HttpStatus;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.access.prepost.PreAuthorize;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import java.util.Optional;
import java.time.Instant;

@RestController
@RequestMapping("/api/v1")
public class ProductionOrderController {

    private static final Logger logger = LoggerFactory.getLogger(ProductionOrderController.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    @Autowired
    private OrderService orderService;

    @Autowired
    private AuthorizationService authService;

    @Autowired
    private RateLimiter rateLimiter;

    @GetMapping("/orders/{orderId}")
    @PreAuthorize("isAuthenticated()")
    public ResponseEntity<OrderDTO> getOrder(
            @PathVariable String orderId,
            @RequestHeader(value = "X-Request-ID", required = false) String requestId) {

        // INPUT VALIDATION: Reject invalid UUID format early
        if (!isValidOrderId(orderId)) {
            logger.warn("Invalid order ID format attempted: {}", sanitizeLogInput(orderId));
            return ResponseEntity.badRequest().build();
        }

        UserContext user = getCurrentUserContext();
        String traceId = requestId != null ? requestId : generateTraceId();

        // RATE LIMITING: Prevent enumeration attacks
        if (!rateLimiter.tryAcquire(user.getUserId(), "order_access")) {
            auditLogger.warn("RATE_LIMIT_EXCEEDED|user={}|endpoint=orders|trace={}", 
                           user.getUserId(), traceId);
            return ResponseEntity.status(HttpStatus.TOO_MANY_REQUESTS).build();
        }

        try {
            // MULTI-TIER AUTHORIZATION CHECK
            AuthorizationResult authResult = authService.checkOrderAccess(
                user, orderId, AccessType.READ);

            if (!authResult.isAuthorized()) {
                // COMPREHENSIVE AUDIT LOG
                auditLogger.warn(
                    "ACCESS_DENIED|user={}|role={}|resource=order|resourceId={}|" +
                    "reason={}|ip={}|trace={}",
                    user.getUserId(), user.getRole(), orderId,
                    authResult.getDenialReason(), user.getIpAddress(), traceId);

                // SECURITY: Return 404 to prevent enumeration
                return ResponseEntity.notFound().build();
            }

            Optional<Order> order = orderService.findById(orderId);

            if (order.isEmpty()) {
                return ResponseEntity.notFound().build();
            }

            // AUDIT SUCCESS: Track all data access for compliance
            auditLogger.info(
                "ACCESS_GRANTED|user={}|role={}|resource=order|resourceId={}|" +
                "accessLevel={}|ip={}|trace={}",
                user.getUserId(), user.getRole(), orderId,
                authResult.getAccessLevel(), user.getIpAddress(), traceId);

            // FIELD-LEVEL FILTERING based on role
            OrderDTO dto = mapToDTO(order.get(), authResult.getAccessLevel());
            return ResponseEntity.ok(dto);

        } catch (Exception e) {
            logger.error("Error processing order request: trace={}", traceId, e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    private boolean isValidOrderId(String orderId) {
        // Use UUID format to prevent enumeration
        return orderId != null && 
               orderId.matches("^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$");
    }

    private String sanitizeLogInput(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n]", "_").substring(0, Math.min(input.length(), 100));
    }

    private UserContext getCurrentUserContext() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        return (UserContext) auth.getPrincipal();
    }

    private String generateTraceId() {
        return java.util.UUID.randomUUID().toString();
    }

    private OrderDTO mapToDTO(Order order, AccessLevel level) {
        OrderDTO dto = new OrderDTO();
        dto.setOrderId(order.getOrderId());
        dto.setStatus(order.getStatus());
        dto.setTotalAmount(order.getTotalAmount());

        // FIELD-LEVEL ACCESS CONTROL
        if (level == AccessLevel.FULL || level == AccessLevel.SUPPORT) {
            dto.setCustomerName(order.getCustomerName());
            dto.setShippingAddress(order.getShippingAddress());
        }
        if (level == AccessLevel.FULL) {
            dto.setInternalNotes(order.getInternalNotes());
            dto.setPaymentDetails(order.getPaymentDetails());
        }
        return dto;
    }
}
```

```java
import org.springframework.stereotype.Service;
import org.springframework.beans.factory.annotation.Autowired;
import java.util.Set;

@Service
public class AuthorizationService {

    @Autowired
    private CustomerAssignmentRepository assignmentRepo;

    @Autowired
    private OrderRepository orderRepo;

    public AuthorizationResult checkOrderAccess(
            UserContext user, String orderId, AccessType accessType) {

        // LAYER 1: Admin bypass with full access
        if (user.hasRole("ROLE_ADMIN")) {
            return AuthorizationResult.granted(AccessLevel.FULL, "admin_role");
        }

        // Fetch order for ownership checks
        Order order = orderRepo.findById(orderId).orElse(null);
        if (order == null) {
            return AuthorizationResult.denied("resource_not_found");
        }

        // LAYER 2: Owner access - users can access their own orders
        if (order.getUserId().equals(user.getUserId())) {
            return AuthorizationResult.granted(AccessLevel.OWNER, "resource_owner");
        }

        // LAYER 3: Support staff - can access assigned customer orders
        if (user.hasRole("ROLE_SUPPORT")) {
            Set<Long> assignedCustomers = assignmentRepo
                .findActiveAssignmentsByStaffId(user.getUserId());

            if (assignedCustomers.contains(order.getUserId())) {
                return AuthorizationResult.granted(AccessLevel.SUPPORT, "support_assignment");
            }
            return AuthorizationResult.denied("customer_not_assigned");
        }

        // LAYER 4: Manager access - can access orders from their department
        if (user.hasRole("ROLE_MANAGER")) {
            if (order.getDepartmentId().equals(user.getDepartmentId())) {
                return AuthorizationResult.granted(AccessLevel.SUPPORT, "department_manager");
            }
            return AuthorizationResult.denied("wrong_department");
        }

        // DEFAULT DENY
        return AuthorizationResult.denied("no_access_rule_matched");
    }
}
```

**Defense in Depth Layers**:

1. **Use UUIDs instead of sequential IDs**:
```java
// In your entity class
@Entity
public class Order {
    @Id
    @GeneratedValue(generator = "UUID")
    @GenericGenerator(name = "UUID", strategy = "org.hibernate.id.UUIDGenerator")
    @Column(columnDefinition = "uuid", updatable = false, nullable = false)
    private UUID orderId;
}
// UUIDs have 2^122 possible values - practically impossible to enumerate
```

2. **Indirect reference maps for sensitive operations**:
```java
@Service
public class IndirectReferenceService {
    private final Cache<String, String> referenceMap = Caffeine.newBuilder()
        .expireAfterWrite(Duration.ofMinutes(30))
        .maximumSize(10000)
        .build();

    public String createIndirectReference(String realId, Long userId) {
        String indirectRef = generateSecureToken();
        String key = userId + ":" + indirectRef;
        referenceMap.put(key, realId);
        return indirectRef;
    }

    public Optional<String> resolveReference(String indirectRef, Long userId) {
        String key = userId + ":" + indirectRef;
        return Optional.ofNullable(referenceMap.getIfPresent(key));
    }
}
```

3. **Anomaly detection for enumeration attempts**:
```java
@Component
public class IDORDetector {
    private final Cache<Long, AccessPattern> userPatterns = Caffeine.newBuilder()
        .expireAfterWrite(Duration.ofHours(1))
        .build();

    public void recordAccess(Long userId, String resourceId, boolean authorized) {
        AccessPattern pattern = userPatterns.get(userId, k -> new AccessPattern());
        pattern.recordAttempt(authorized);

        // Alert on suspicious patterns
        if (pattern.getDeniedCount() > 10 && pattern.getDeniedRatio() > 0.5) {
            alertSecurityTeam(userId, "Potential IDOR enumeration detected");
            // Consider temporary account lockout
        }
    }
}
```

**Additional Protections**:
- **Database-level enforcement**: Use PostgreSQL Row-Level Security (RLS) policies as ultimate backstop
- **API gateway validation**: Implement authorization checks at the API gateway level for defense in depth
- **Penetration testing**: Include IDOR-specific test cases in automated security scans using tools like Burp Suite's Autorize extension
- **Monitoring dashboards**: Track 404/403 ratios per user to detect enumeration in real-time
- **Immutable audit logs**: Ship audit logs to a separate write-once storage for forensic analysis

This is a classic IDOR (Insecure Direct Object Reference) vulnerability - one of the most common and dangerous access control flaws. If you're directly using the invoice ID from the URL without verifying ownership, any authenticated user can download any invoice by guessing IDs.

**VULNERABLE CODE**:

```go
package main

import (
	"database/sql"
	"net/http"
	"strconv"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

var db *sql.DB

// VULNERABLE: No ownership verification
func getInvoice(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	invoiceID, err := strconv.Atoi(vars["id"])
	if err != nil {
		http.Error(w, "Invalid invoice ID", http.StatusBadRequest)
		return
	}

	// VULNERABILITY: Only checks if invoice exists, not ownership!
	var invoiceData []byte
	var customerName string
	err = db.QueryRow(
		"SELECT pdf_data, customer_name FROM invoices WHERE id = $1",
		invoiceID,
	).Scan(&invoiceData, &customerName)

	if err == sql.ErrNoRows {
		http.Error(w, "Invoice not found", http.StatusNotFound)
		return
	}
	if err != nil {
		http.Error(w, "Server error", http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/pdf")
	w.Write(invoiceData)
}
```

**Attack Payload**:
```bash
# Attacker enumerates invoice IDs to access other users' invoices
for i in $(seq 1 10000); do
  curl -H "Authorization: Bearer $ATTACKER_TOKEN" \
       -o "invoice_$i.pdf" \
       "https://api.example.com/invoices/$i"
done
```

**Why This Is Dangerous**:
- Any authenticated user can access ANY invoice by changing the ID parameter
- Sequential integer IDs make enumeration trivial (1, 2, 3...)
- Exposes sensitive financial data: names, addresses, purchase history, payment info
- Similar to Parler breach where attackers downloaded 70TB of private user data

**SECURE VERSION**:

```go
package main

import (
	"database/sql"
	"log"
	"net/http"
	"strconv"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

var db *sql.DB

// getUserIDFromContext extracts authenticated user ID from JWT/session
func getUserIDFromContext(r *http.Request) (int, error) {
	// In production, extract from validated JWT claims
	userID := r.Context().Value("user_id")
	if userID == nil {
		return 0, http.ErrNoCookie
	}
	return userID.(int), nil
}

// SECURE: Verifies resource ownership before access
func getInvoiceSecure(w http.ResponseWriter, r *http.Request) {
	// Get authenticated user
	userID, err := getUserIDFromContext(r)
	if err != nil {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	vars := mux.Vars(r)
	invoiceID, err := strconv.Atoi(vars["id"])
	if err != nil {
		http.Error(w, "Invalid invoice ID", http.StatusBadRequest)
		return
	}

	// SECURITY: Query includes ownership check in WHERE clause
	var invoiceData []byte
	err = db.QueryRow(
		`SELECT pdf_data FROM invoices 
		 WHERE id = $1 AND user_id = $2`,
		invoiceID,
		userID, // Only returns if user owns this invoice
	).Scan(&invoiceData)

	if err == sql.ErrNoRows {
		// SECURITY: Don't reveal if invoice exists for other users
		log.Printf("IDOR attempt: user=%d tried invoice=%d", userID, invoiceID)
		http.Error(w, "Invoice not found", http.StatusNotFound)
		return
	}
	if err != nil {
		log.Printf("Database error: %v", err)
		http.Error(w, "Server error", http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/pdf")
	w.Header().Set("Content-Disposition", "attachment; filename=invoice.pdf")
	w.Write(invoiceData)
}
```

**Key Security Controls**:
- **Ownership verification in query**: The WHERE clause requires both `id = $1 AND user_id = $2`, ensuring users can only access their own invoices
- **Consistent error response**: Returns 404 for both non-existent and unauthorized resources, preventing attackers from enumerating valid IDs
- **Audit logging**: Logs potential IDOR attempts for security monitoring

