			return true
		}
	}
	return false
}

// CanAccessInvoice implements authorization logic
func (s *AuthorizationService) CanAccessInvoice(ctx context.Context, user *User, invoiceUUID string) (bool, string) {
	// Admin bypass with audit trail
	if user.HasRole("admin") || user.HasRole("billing_admin") {
		return true, "admin_access"
	}

	// Check ownership
	var ownerID int
	err := s.db.QueryRowContext(ctx,
		"SELECT user_id FROM invoices WHERE uuid = $1",
		invoiceUUID,
	).Scan(&ownerID)

	if err == sql.ErrNoRows {
		return false, "not_found"
	}
	if err != nil {
		log.Printf("Authorization DB error: %v", err)
		return false, "error"
	}

	if ownerID == user.ID {
		return true, "owner_access"
	}

	// Check delegated access (e.g., accountant for business)
	var delegatedAccess bool
	err = s.db.QueryRowContext(ctx,
		`SELECT EXISTS(
			SELECT 1 FROM invoice_delegates 
			WHERE invoice_uuid = $1 
			AND delegate_user_id = $2 
			AND expires_at > NOW()
		)`,
		invoiceUUID, user.ID,
	).Scan(&delegatedAccess)

	if err == nil && delegatedAccess {
		return true, "delegated_access"
	}

	return false, "unauthorized"
}

// getRateLimiter returns per-user rate limiter
func (s *AuthorizationService) getRateLimiter(userID int) *rate.Limiter {
	if limiter, exists := s.rateLimiter[userID]; exists {
		return limiter
	}
	// 10 requests per second, burst of 20
	limiter := rate.NewLimiter(10, 20)
	s.rateLimiter[userID] = limiter
	return limiter
}

