			Timestamp:  time.Now(),
			UserID:     user.ID,
			Action:     "invoice_access",
			IPAddress:  r.RemoteAddr,
			Result:     "rate_limited",
		})
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	vars := mux.Vars(r)
	invoiceUUID := vars["uuid"]

	// Input validation: UUID format check
	if !validateUUID(invoiceUUID) {
		logAuditEvent(AuditLog{
			Timestamp:  time.Now(),
			UserID:     user.ID,
			Action:     "invoice_access",
			ResourceID: invoiceUUID,
			IPAddress:  r.RemoteAddr,
			Result:     "invalid_id",
		})
		http.Error(w, "Invalid invoice ID", http.StatusBadRequest)
		return
	}

