		UserID:     user.ID,
		Action:     "invoice_access",
		ResourceID: invoiceUUID,
		IPAddress:  r.RemoteAddr,
		Result:     map[bool]string{true: "allowed", false: "denied"}[allowed],
		Reason:     reason,
	})

	if !allowed {
