**Attack Payload**:
```bash
# Attacker enumerates all user profiles by incrementing ID
for i in {1..10000}; do
  curl -s "https://victim.com/api/profile?user_id=$i" >> stolen_data.json
  sleep 0.1
done
```

**Why This Is Dangerous**:
- Anyone can access any user's profile by changing the ID in the URL
- No verification that the requesting user owns or is authorized to view the data
- Predictable sequential IDs make enumeration trivial
- Sensitive data (SSN, address, phone) exposed to unauthorized users
- Automated scraping can harvest entire database quickly

**SECURE VERSION**:

```php
<?php
require_once 'config.php';
require_once 'middleware/auth.php';

class UserController {
    private $pdo;
    private $logger;

    public function __construct(PDO $pdo, Logger $logger) {
        $this->pdo = $pdo;
        $this->logger = $logger;
    }

    public function getProfile($requestedUserId) {
        // SECURITY CONTROL 1: Verify user is authenticated
        $authenticatedUser = AuthMiddleware::getCurrentUser();
        if (!$authenticatedUser) {
            http_response_code(401);
            echo json_encode(['error' => 'Authentication required']);
            return;
        }

        // SECURITY CONTROL 2: Authorization check - can this user view this profile?
        if (!$this->canViewProfile($authenticatedUser, $requestedUserId)) {
            // Log potential IDOR attempt
            $this->logger->warning('IDOR attempt detected', [
                'authenticated_user' => $authenticatedUser['id'],
                'requested_user' => $requestedUserId,
                'ip' => $_SERVER['REMOTE_ADDR'],
                'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown'
            ]);

            // Return 404 to prevent enumeration (don't reveal existence)
            http_response_code(404);
            echo json_encode(['error' => 'Profile not found']);
            return;
        }

        // SECURITY CONTROL 3: Input validation
        $requestedUserId = filter_var($requestedUserId, FILTER_VALIDATE_INT);
        if ($requestedUserId === false || $requestedUserId <= 0) {
            http_response_code(400);
            echo json_encode(['error' => 'Invalid user ID']);
            return;
        }

        // Fetch only non-sensitive fields based on relationship
        $fields = $this->getAllowedFields($authenticatedUser, $requestedUserId);
        $stmt = $this->pdo->prepare(
            "SELECT " . implode(', ', $fields) . " FROM users WHERE id = ?"
        );
        $stmt->execute([$requestedUserId]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        header('Content-Type: application/json');
        echo json_encode($user);
    }

    private function canViewProfile($viewer, $targetId) {
        // Users can always view their own profile
        if ($viewer['id'] === $targetId) {
            return true;
        }

        // Admins can view any profile
        if ($viewer['role'] === 'admin') {
            return true;
        }

        // Check if users are connected (friends, same organization, etc.)
        $stmt = $this->pdo->prepare(
            "SELECT 1 FROM user_connections 
             WHERE (user_a = ? AND user_b = ?) OR (user_a = ? AND user_b = ?)
             AND status = 'approved'"
        );
        $stmt->execute([$viewer['id'], $targetId, $targetId, $viewer['id']]);

        return $stmt->fetch() !== false;
    }

    private function getAllowedFields($viewer, $targetId) {
        // Own profile - full access
        if ($viewer['id'] === $targetId) {
            return ['id', 'username', 'email', 'phone', 'address', 'created_at'];
        }

        // Connected users - limited fields
        return ['id', 'username', 'bio', 'avatar_url'];
    }
}
```

**Key Security Controls**:
- **Authentication verification**: Every request must come from an authenticated user with a valid session
- **Authorization check**: Verify the authenticated user has permission to access the requested resource
- **Principle of least privilege**: Return only the fields the user is authorized to see based on their relationship
- **Security logging**: Log potential IDOR attempts for monitoring and incident response
- **Consistent error responses**: Return 404 for unauthorized access to prevent enumeration attacks

This is a more complex authorization scenario that requires Role-Based Access Control (RBAC) combined with resource ownership verification. Many enterprise breaches occur when companies implement user-level IDOR protection but forget organization-level boundaries. The 2023 Microsoft Power Platform vulnerability (CVE-2023-24933) exposed this exact pattern where users could access other organizations' data through API manipulation.

**PRODUCTION PATTERN**:

```php
<?php
require_once 'vendor/autoload.php';

use App\Security\AuthMiddleware;
use App\Security\RateLimiter;
use App\Logging\AuditLogger;

class DocumentController {
    private PDO $pdo;
    private AuditLogger $auditLogger;
    private RateLimiter $rateLimiter;

    // Define permission matrix
    private const PERMISSIONS = [
        'owner' => ['read', 'write', 'delete', 'share', 'manage_access'],
        'admin' => ['read', 'write', 'delete', 'share'],
        'editor' => ['read', 'write'],
        'viewer' => ['read'],
        'guest' => ['read']  // Only for explicitly shared docs
    ];

    public function __construct(PDO $pdo, AuditLogger $auditLogger, RateLimiter $rateLimiter) {
        $this->pdo = $pdo;
        $this->auditLogger = $auditLogger;
        $this->rateLimiter = $rateLimiter;
    }

    public function getDocument(string $documentId): void {
        // LAYER 1: Rate limiting to prevent enumeration attacks
        $clientIp = $_SERVER['REMOTE_ADDR'];
        if (!$this->rateLimiter->checkLimit($clientIp, 'document_access', 100, 60)) {
            $this->auditLogger->warning('Rate limit exceeded', [
                'ip' => $clientIp,
                'action' => 'document_access'
            ]);
            $this->respondError(429, 'Too many requests');
            return;
        }

        // LAYER 2: Authentication
        $user = AuthMiddleware::getCurrentUser();
        if (!$user) {
            $this->respondError(401, 'Authentication required');
            return;
        }

        // LAYER 3: Input validation - use UUIDs instead of sequential IDs
        if (!$this->isValidUuid($documentId)) {
            $this->respondError(400, 'Invalid document identifier');
            return;
        }

        // LAYER 4: Fetch document with organization context
        $document = $this->fetchDocumentSecurely($documentId);
        if (!$document) {
            // Consistent response to prevent enumeration
            $this->respondError(404, 'Document not found');
            return;
        }

        // LAYER 5: Multi-level authorization check
        $accessResult = $this->checkDocumentAccess($user, $document, 'read');

        if (!$accessResult['allowed']) {
            // Detailed audit logging for security monitoring
            $this->auditLogger->alert('Unauthorized document access attempt', [
                'user_id' => $user['id'],
                'user_org' => $user['organization_id'],
                'document_id' => $documentId,
                'document_org' => $document['organization_id'],
                'reason' => $accessResult['reason'],
                'ip' => $clientIp,
                'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown',
                'timestamp' => date('c')
            ]);

            // Generic 404 to prevent information leakage
            $this->respondError(404, 'Document not found');
            return;
        }

        // LAYER 6: Field-level access control
        $sanitizedDocument = $this->filterDocumentFields($document, $accessResult['role']);

        // Successful access audit log
        $this->auditLogger->info('Document accessed', [
            'user_id' => $user['id'],
            'document_id' => $documentId,
            'role' => $accessResult['role'],
            'ip' => $clientIp
        ]);

        $this->respondSuccess($sanitizedDocument);
    }

    private function checkDocumentAccess(array $user, array $document, string $action): array {
        // Check 1: Is user the document owner?
        if ($document['owner_id'] === $user['id']) {
            return ['allowed' => true, 'role' => 'owner', 'reason' => 'owner'];
        }

        // Check 2: Is user in the same organization?
        if ($document['organization_id'] !== $user['organization_id']) {
            // Check for cross-org sharing (explicit shares only)
            $crossOrgAccess = $this->checkCrossOrgShare($user['id'], $document['id']);
            if (!$crossOrgAccess) {
                return ['allowed' => false, 'role' => null, 'reason' => 'org_boundary'];
            }
            // Use the shared permission level
            if (in_array($action, self::PERMISSIONS[$crossOrgAccess['role']] ?? [])) {
                return ['allowed' => true, 'role' => $crossOrgAccess['role'], 'reason' => 'cross_org_share'];
            }
            return ['allowed' => false, 'role' => null, 'reason' => 'insufficient_cross_org_permission'];
        }

        // Check 3: User's organization role
        $orgRole = $this->getUserOrgRole($user['id'], $user['organization_id']);

        // Check 4: Document-specific permissions
        $docPermission = $this->getDocumentPermission($user['id'], $document['id']);

        // Use the higher of org role or document-specific permission
        $effectiveRole = $this->getHigherRole($orgRole, $docPermission);

        // Check 5: Does the effective role have the required permission?
        $allowedActions = self::PERMISSIONS[$effectiveRole] ?? [];

        if (in_array($action, $allowedActions)) {
            return ['allowed' => true, 'role' => $effectiveRole, 'reason' => 'role_permission'];
        }

        return ['allowed' => false, 'role' => null, 'reason' => 'insufficient_permission'];
    }

    private function fetchDocumentSecurely(string $documentId): ?array {
        // Parameterized query prevents SQL injection
        $stmt = $this->pdo->prepare("
            SELECT d.id, d.title, d.content, d.owner_id, d.organization_id,
                   d.classification, d.created_at, d.updated_at,
                   o.name as org_name
            FROM documents d
            JOIN organizations o ON d.organization_id = o.id
            WHERE d.id = ? AND d.deleted_at IS NULL
        ");
        $stmt->execute([$documentId]);
        return $stmt->fetch(PDO::FETCH_ASSOC) ?: null;
    }

    private function getDocumentPermission(int $userId, string $documentId): ?string {
        $stmt = $this->pdo->prepare("
            SELECT role FROM document_permissions
            WHERE user_id = ? AND document_id = ? AND expires_at > NOW()
        ");
        $stmt->execute([$userId, $documentId]);
        $result = $stmt->fetch(PDO::FETCH_ASSOC);
        return $result['role'] ?? null;
    }

    private function checkCrossOrgShare(int $userId, string $documentId): ?array {
        $stmt = $this->pdo->prepare("
            SELECT role, granted_by, granted_at, expires_at
            FROM document_shares
            WHERE user_id = ? AND document_id = ? 
            AND (expires_at IS NULL OR expires_at > NOW())
            AND revoked_at IS NULL
        ");
        $stmt->execute([$userId, $documentId]);
        return $stmt->fetch(PDO::FETCH_ASSOC) ?: null;
    }

    private function getUserOrgRole(int $userId, int $orgId): ?string {
        $stmt = $this->pdo->prepare("
            SELECT role FROM organization_members
            WHERE user_id = ? AND organization_id = ? AND status = 'active'
        ");
        $stmt->execute([$userId, $orgId]);
        $result = $stmt->fetch(PDO::FETCH_ASSOC);
        return $result['role'] ?? null;
    }

    private function getHigherRole(?string $role1, ?string $role2): string {
        $roleHierarchy = ['owner' => 5, 'admin' => 4, 'editor' => 3, 'viewer' => 2, 'guest' => 1];
        $rank1 = $roleHierarchy[$role1] ?? 0;
        $rank2 = $roleHierarchy[$role2] ?? 0;
        return $rank1 >= $rank2 ? ($role1 ?? 'guest') : ($role2 ?? 'guest');
    }

    private function filterDocumentFields(array $document, string $role): array {
        $baseFields = ['id', 'title', 'created_at'];

        $roleFields = [
            'owner' => ['content', 'classification', 'updated_at', 'org_name', 'owner_id'],
            'admin' => ['content', 'classification', 'updated_at', 'org_name'],
            'editor' => ['content', 'updated_at'],
            'viewer' => ['content'],
            'guest' => []
        ];

        $allowedFields = array_merge($baseFields, $roleFields[$role] ?? []);
        return array_intersect_key($document, array_flip($allowedFields));
    }

    private function isValidUuid(string $uuid): bool {
        return preg_match('/^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i', $uuid) === 1;
    }

    private function respondError(int $code, string $message): void {
        http_response_code($code);
        header('Content-Type: application/json');
        echo json_encode(['error' => $message]);
    }

    private function respondSuccess(array $data): void {
        http_response_code(200);
        header('Content-Type: application/json');
        header('X-Content-Type-Options: nosniff');
        header('Cache-Control: private, no-cache, no-store, must-revalidate');
        echo json_encode(['data' => $data]);
    }
}
