// Implemented in RateLimiter class using Redis
public function checkLimit(string $key, string $action, int $limit, int $window): bool {
    $redisKey = "ratelimit:{$action}:{$key}";
    $current = $this->redis->incr($redisKey);
    if ($current === 1) {
        $this->redis->expire($redisKey, $window);
    }
    return $current <= $limit;
}
