**PRODUCTION PATTERN**:

```csharp
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize]
    public class ProfileController : ControllerBase
    {
        private readonly ApplicationDbContext _context;
        private readonly IAuthorizationService _authorizationService;
        private readonly ILogger<ProfileController> _logger;

        public ProfileController(
            ApplicationDbContext context,
            IAuthorizationService authorizationService,
            ILogger<ProfileController> logger)
        {
            _context = context;
            _authorizationService = authorizationService;
            _logger = logger;
        }

        private int GetCurrentUserId()
        {
            var claim = User.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            return int.TryParse(claim, out int id) ? id : throw new UnauthorizedAccessException();
        }

        private bool IsAdmin() => User.IsInRole("Admin") || User.IsInRole("SuperAdmin");

        // Get own profile (regular users) or any profile (admins)
        [HttpGet("{userId?}")]
        public async Task<IActionResult> GetProfile(int? userId = null)
        {
            var currentUserId = GetCurrentUserId();
            var targetUserId = userId ?? currentUserId;

            // AUTHORIZATION CHECK: Only admins can view other users' profiles
            if (targetUserId != currentUserId)
            {
                if (!IsAdmin())
                {
                    _logger.LogWarning(
                        "SECURITY: User {CurrentUserId} attempted unauthorized access to profile {TargetUserId}",
                        currentUserId, targetUserId);
                    return Forbid();
                }

                _logger.LogInformation(
                    "Admin {AdminId} accessed profile of user {TargetUserId}",
                    currentUserId, targetUserId);
            }

            var profile = await _context.UserProfiles
                .AsNoTracking()
                .Select(p => new ProfileDto
                {
                    UserId = p.UserId,
                    DisplayName = p.DisplayName,
                    Email = p.Email,
                    // Only include sensitive data for own profile or admin
                    PhoneNumber = (targetUserId == currentUserId || IsAdmin()) ? p.PhoneNumber : null,
                    Address = (targetUserId == currentUserId || IsAdmin()) ? p.Address : null
                })
                .FirstOrDefaultAsync(p => p.UserId == targetUserId);

            return profile == null ? NotFound() : Ok(profile);
        }

        // Document access with sharing permissions
        [HttpGet("documents/{documentId}")]
        public async Task<IActionResult> GetDocument(Guid documentId)
        {
            var currentUserId = GetCurrentUserId();

            var document = await _context.Documents
                .Include(d => d.SharedWith)
                .AsNoTracking()
                .FirstOrDefaultAsync(d => d.Id == documentId);

            if (document == null)
            {
                // Don't reveal document existence to unauthorized users
                return NotFound();
            }

            // AUTHORIZATION: Check ownership OR sharing permission OR admin
            var hasAccess = document.OwnerId == currentUserId ||
                            document.SharedWith.Any(s => s.UserId == currentUserId && s.IsActive) ||
                            IsAdmin();

            if (!hasAccess)
            {
                _logger.LogWarning(
                    "SECURITY: User {UserId} denied access to document {DocumentId}",
                    currentUserId, documentId);
                // Return 404, not 403, to prevent enumeration
                return NotFound();
            }

            // Determine access level
            var accessLevel = document.OwnerId == currentUserId ? "owner" :
                              IsAdmin() ? "admin" : "shared";

            _logger.LogInformation(
                "User {UserId} accessed document {DocumentId} with level {AccessLevel}",
                currentUserId, documentId, accessLevel);

            return Ok(new DocumentDto
            {
                Id = document.Id,
                Title = document.Title,
                Content = document.Content,
                AccessLevel = accessLevel,
                CanEdit = document.OwnerId == currentUserId ||
                          document.SharedWith.Any(s => s.UserId == currentUserId && s.CanEdit)
            });
        }

        // Share document with another user
        [HttpPost("documents/{documentId}/share")]
        public async Task<IActionResult> ShareDocument(Guid documentId, [FromBody] ShareRequestDto request)
        {
            var currentUserId = GetCurrentUserId();

            var document = await _context.Documents
                .FirstOrDefaultAsync(d => d.Id == documentId);

            // Only owner can share (or admin)
            if (document == null)
                return NotFound();

            if (document.OwnerId != currentUserId && !IsAdmin())
            {
                _logger.LogWarning(
                    "SECURITY: User {UserId} attempted to share document {DocumentId} they don't own",
                    currentUserId, documentId);
                return Forbid();
            }

            // Verify target user exists before sharing
            var targetUserExists = await _context.Users.AnyAsync(u => u.Id == request.TargetUserId);
            if (!targetUserExists)
                return BadRequest("Target user not found");

            // Prevent duplicate shares
            var existingShare = await _context.DocumentShares
                .FirstOrDefaultAsync(s => s.DocumentId == documentId && s.UserId == request.TargetUserId);

            if (existingShare != null)
            {
                existingShare.CanEdit = request.CanEdit;
                existingShare.IsActive = true;
            }
            else
            {
                _context.DocumentShares.Add(new DocumentShare
                {
                    DocumentId = documentId,
                    UserId = request.TargetUserId,
                    CanEdit = request.CanEdit,
                    SharedByUserId = currentUserId,
                    SharedAt = DateTime.UtcNow,
                    IsActive = true
                });
            }

            await _context.SaveChangesAsync();

            _logger.LogInformation(
                "User {OwnerId} shared document {DocumentId} with user {TargetUserId}",
                currentUserId, documentId, request.TargetUserId);

            return Ok(new { Message = "Document shared successfully" });
        }
    }

    // Custom authorization handler for complex scenarios
    public class DocumentAuthorizationHandler : AuthorizationHandler<DocumentAccessRequirement, Document>
    {
        private readonly ApplicationDbContext _context;

        public DocumentAuthorizationHandler(ApplicationDbContext context)
        {
            _context = context;
        }

        protected override async Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            DocumentAccessRequirement requirement,
            Document document)
        {
            var userIdClaim = context.User.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            if (!int.TryParse(userIdClaim, out int userId))
            {
                context.Fail();
                return;
            }

            // Check ownership
            if (document.OwnerId == userId)
            {
                context.Succeed(requirement);
                return;
            }

            // Check admin role
            if (context.User.IsInRole("Admin"))
            {
                context.Succeed(requirement);
                return;
            }

            // Check sharing permissions
            var hasShare = await _context.DocumentShares
                .AnyAsync(s => s.DocumentId == document.Id &&
                              s.UserId == userId &&
                              s.IsActive &&
                              (!requirement.RequiresEdit || s.CanEdit));

            if (hasShare)
            {
                context.Succeed(requirement);
            }
        }
    }

    public class DocumentAccessRequirement : IAuthorizationRequirement
    {
        public bool RequiresEdit { get; }
        public DocumentAccessRequirement(bool requiresEdit = false)
        {
            RequiresEdit = requiresEdit;
        }
    }
}
```

