Using order IDs directly from URLs without proper authorization checks is extremely dangerous. This creates an IDOR (Insecure Direct Object Reference) vulnerability that allows attackers to access any user's orders by simply changing the ID in the URL.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const { Pool } = require('pg');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// VULNERABLE: No authorization check - any authenticated user can view any order
app.get('/api/orders/:orderId', async (req, res) => {
  try {
    const { orderId } = req.params;

    // Directly fetches order without checking ownership
    const result = await pool.query(
      'SELECT * FROM orders WHERE id = $1',
      [orderId]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Order not found' });
    }

    // Returns order data regardless of who owns it
    res.json(result.rows[0]);
  } catch (error) {
    res.status(500).json({ error: 'Server error' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```bash
# Attacker enumerates order IDs to access other users' orders
for i in {1..10000}; do
  curl -H "Authorization: Bearer $ATTACKER_TOKEN" \
       https://api.example.com/api/orders/$i >> stolen_orders.json
done
```

**Why This Is Dangerous**:
- Any authenticated user can access ANY order by changing the orderId parameter
- Sequential IDs make enumeration trivial (order 1, 2, 3, etc.)
- Exposes sensitive data: addresses, payment info, purchase history
- No audit trail of who accessed which orders
- Violates data privacy regulations (GDPR, CCPA)

**SECURE VERSION**:

```javascript
const express = require('express');
const { Pool } = require('pg');
const jwt = require('jsonwebtoken');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// Middleware to extract and validate user from JWT
const authenticateUser = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;
    next();
  } catch (error) {
    return res.status(401).json({ error: 'Invalid token' });
  }
};

// SECURE: Authorization check ensures users can only access their own orders
app.get('/api/orders/:orderId', authenticateUser, async (req, res) => {
  try {
    const { orderId } = req.params;
    const userId = req.user.id;

    // Validate orderId format to prevent injection
    if (!/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(orderId)) {
      return res.status(400).json({ error: 'Invalid order ID format' });
    }

    // PRIMARY DEFENSE: Query includes user_id ownership check
    const result = await pool.query(
      'SELECT id, status, total, created_at, items FROM orders WHERE id = $1 AND user_id = $2',
      [orderId, userId]
    );

    if (result.rows.length === 0) {
      // Intentionally vague - don't reveal if order exists but belongs to someone else
      return res.status(404).json({ error: 'Order not found' });
    }

    res.json(result.rows[0]);
  } catch (error) {
    console.error('Order fetch error:', error.message);
    res.status(500).json({ error: 'Server error' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Ownership verification**: Query includes `AND user_id = $2` to ensure users only access their own data
- **UUID format**: Using UUIDs instead of sequential integers prevents enumeration attacks
- **Vague error messages**: Same 404 response whether order doesn't exist or belongs to someone else (prevents information leakage)
- **Input validation**: Validates UUID format before database query

Excellent question! Role-based access control (RBAC) and multi-party resource access require a more sophisticated authorization layer. Here's a production-ready pattern:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { Pool } = require('pg');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');
const winston = require('winston');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// Security audit logger
const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Rate limiting to prevent enumeration attacks
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  message: { error: 'Too many requests, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Role definitions with permissions
const ROLES = {
  CUSTOMER: 'customer',
  SELLER: 'seller',
  SUPPORT: 'support',
  ADMIN: 'admin'
};

const PERMISSIONS = {
  ORDER_READ_OWN: 'order:read:own',
  ORDER_READ_SOLD: 'order:read:sold',
  ORDER_READ_ANY: 'order:read:any',
  ORDER_MODIFY_OWN: 'order:modify:own',
  ORDER_MODIFY_ANY: 'order:modify:any'
};

const ROLE_PERMISSIONS = {
  [ROLES.CUSTOMER]: [PERMISSIONS.ORDER_READ_OWN, PERMISSIONS.ORDER_MODIFY_OWN],
  [ROLES.SELLER]: [PERMISSIONS.ORDER_READ_OWN, PERMISSIONS.ORDER_READ_SOLD],
  [ROLES.SUPPORT]: [PERMISSIONS.ORDER_READ_ANY],
  [ROLES.ADMIN]: Object.values(PERMISSIONS)
};

// Authentication middleware
const authenticate = async (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);

    // Verify user still exists and is active
    const userResult = await pool.query(
      'SELECT id, role, is_active FROM users WHERE id = $1',
      [decoded.id]
    );

    if (userResult.rows.length === 0 || !userResult.rows[0].is_active) {
      return res.status(401).json({ error: 'Invalid session' });
    }

    req.user = {
      id: userResult.rows[0].id,
      role: userResult.rows[0].role,
      permissions: ROLE_PERMISSIONS[userResult.rows[0].role] || []
    };
    next();
  } catch (error) {
    return res.status(401).json({ error: 'Invalid token' });
  }
};

// Authorization service for complex access control
class OrderAuthorizationService {
  static async canAccessOrder(userId, userRole, userPermissions, orderId) {
    // Admin/support can access any order
    if (userPermissions.includes(PERMISSIONS.ORDER_READ_ANY)) {
      return { allowed: true, reason: 'admin_access' };
    }

    // Check if user is buyer or seller of this order
    const result = await pool.query(
      `SELECT buyer_id, seller_id FROM orders WHERE id = $1`,
      [orderId]
    );

    if (result.rows.length === 0) {
      return { allowed: false, reason: 'order_not_found' };
    }

    const order = result.rows[0];

    // Buyer access check
    if (order.buyer_id === userId && userPermissions.includes(PERMISSIONS.ORDER_READ_OWN)) {
      return { allowed: true, reason: 'buyer_access' };
    }

    // Seller access check
    if (order.seller_id === userId && userPermissions.includes(PERMISSIONS.ORDER_READ_SOLD)) {
      return { allowed: true, reason: 'seller_access' };
    }

    return { allowed: false, reason: 'unauthorized' };
  }
}

// Secure order endpoint with full RBAC
app.get('/api/orders/:orderId', apiLimiter, authenticate, async (req, res) => {
  const requestId = require('crypto').randomUUID();
  const startTime = Date.now();

  try {
    const { orderId } = req.params;
    const { id: userId, role, permissions } = req.user;

    // Validate UUID format
    if (!/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(orderId)) {
      auditLogger.warn({
        event: 'invalid_order_id_format',
        requestId,
        userId,
        orderId: orderId.substring(0, 50), // Truncate for safety
        ip: req.ip
      });
      return res.status(400).json({ error: 'Invalid order ID format' });
    }

    // Authorization check
    const authResult = await OrderAuthorizationService.canAccessOrder(
      userId, role, permissions, orderId
    );

    // Audit log the access attempt
    auditLogger.info({
      event: 'order_access_attempt',
      requestId,
      userId,
      userRole: role,
      orderId,
      authorized: authResult.allowed,
      reason: authResult.reason,
      ip: req.ip,
      userAgent: req.get('User-Agent')
    });

    if (!authResult.allowed) {
      // Same response for not found and unauthorized (prevents enumeration)
      return res.status(404).json({ error: 'Order not found' });
    }

    // Fetch order with role-appropriate fields
    let query;
    let fields;

    if (permissions.includes(PERMISSIONS.ORDER_READ_ANY)) {
      // Admin sees everything including internal notes
      fields = 'id, status, total, created_at, items, buyer_id, seller_id, internal_notes, shipping_address';
    } else if (authResult.reason === 'seller_access') {
      // Seller sees limited buyer info
      fields = 'id, status, total, created_at, items, shipping_city, shipping_state';
    } else {
      // Buyer sees their full order
      fields = 'id, status, total, created_at, items, shipping_address, tracking_number';
    }

    const result = await pool.query(
      `SELECT ${fields} FROM orders WHERE id = $1`,
      [orderId]
    );

    // Performance logging
    const duration = Date.now() - startTime;
    if (duration > 1000) {
      console.warn(`Slow order query: ${duration}ms for order ${orderId}`);
    }

    res.json({
      data: result.rows[0],
      meta: {
        accessLevel: authResult.reason,
        requestId
      }
    });

  } catch (error) {
    auditLogger.error({
      event: 'order_access_error',
      requestId,
      userId: req.user?.id,
      error: error.message,
      stack: process.env.NODE_ENV === 'development' ? error.stack : undefined
    });

    res.status(500).json({ 
      error: 'Server error',
      requestId // Include for support reference
    });
  }
});

// Health check for monitoring
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

app.listen(3000, () => {
  console.log('Server running with IDOR protection enabled');
});
```

**Defense in Depth Layers**:

1. **Authentication Layer**: JWT validation with database verification that user is still active
