Excellent question! Real applications need hierarchical authorization with multiple roles and scopes. Here's a production-ready pattern with Role-Based Access Control (RBAC) that handles admin access, regional support staff, and regular users.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strconv"
	"time"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
	"golang.org/x/time/rate"
)

// Role definitions with explicit permissions
type Role string

const (
	RoleUser           Role = "user"
	RoleRegionalSupport Role = "regional_support"
	RoleAdmin          Role = "admin"
	RoleSuperAdmin     Role = "super_admin"
)

type AuthenticatedUser struct {
	ID       int
	Role     Role
	RegionID int
	Email    string
}

type User struct {
	ID        int     `json:"id"`
	Email     string  `json:"email"`
	FullName  string  `json:"full_name"`
	SSN       string  `json:"ssn,omitempty"`
	Balance   float64 `json:"balance"`
	RegionID  int     `json:"region_id"`
}

type AuditLog struct {
	Timestamp    time.Time
	ActorID      int
	ActorRole    Role
	Action       string
	ResourceType string
	ResourceID   int
	Allowed      bool
	IPAddress    string
	Reason       string
}

type contextKey string

const authUserKey contextKey = "authUser"

var (
	db      *sql.DB
	limiter = rate.NewLimiter(rate.Every(time.Second), 100)
)

// AuthorizationService handles all access control decisions
type AuthorizationService struct {
	db *sql.DB
}

// CanAccessAccount implements hierarchical authorization logic
func (a *AuthorizationService) CanAccessAccount(actor *AuthenticatedUser, targetAccountID int) (bool, string) {
	// Super admins can access everything
	if actor.Role == RoleSuperAdmin {
		return true, "super_admin_access"
	}

	// Regular admins can access all non-admin accounts
	if actor.Role == RoleAdmin {
		var targetRole string
		err := a.db.QueryRow(
			"SELECT role FROM users WHERE id = $1",
			targetAccountID,
		).Scan(&targetRole)
		if err != nil {
			return false, "target_not_found"
		}
		// Admins cannot access other admin accounts
		if targetRole == string(RoleAdmin) || targetRole == string(RoleSuperAdmin) {
			return false, "admin_to_admin_denied"
		}
		return true, "admin_access"
	}

	// Regional support can only access accounts in their region
	if actor.Role == RoleRegionalSupport {
		var targetRegionID int
		var targetRole string
		err := a.db.QueryRow(
			"SELECT region_id, role FROM users WHERE id = $1",
			targetAccountID,
		).Scan(&targetRegionID, &targetRole)
		if err != nil {
			return false, "target_not_found"
		}
		// Support cannot access admin accounts
		if targetRole == string(RoleAdmin) || targetRole == string(RoleSuperAdmin) {
			return false, "support_to_admin_denied"
		}
		if targetRegionID != actor.RegionID {
			return false, "region_mismatch"
		}
		return true, "regional_support_access"
	}

	// Regular users can only access their own account
	if actor.ID == targetAccountID {
		return true, "self_access"
	}

	return false, "unauthorized"
}

// DataMasking based on role - support staff see limited PII
func (a *AuthorizationService) MaskSensitiveData(user *User, actorRole Role, isSelfAccess bool) {
	if isSelfAccess {
		return // Users see their own full data
	}

	switch actorRole {
	case RoleSuperAdmin:
		return // Full access
	case RoleAdmin:
		// Mask partial SSN
		if len(user.SSN) >= 4 {
			user.SSN = "***-**-" + user.SSN[len(user.SSN)-4:]
		}
	case RoleRegionalSupport:
		// Support sees no SSN, masked balance
		user.SSN = "[REDACTED]"
		user.Balance = 0 // Or show range like "$1000-5000"
	default:
		user.SSN = "[REDACTED]"
		user.Balance = 0
	}
}

// AuditLogger for compliance and security monitoring
func logAuditEvent(log AuditLog) {
	_, err := db.Exec(`
		INSERT INTO audit_logs 
		(timestamp, actor_id, actor_role, action, resource_type, resource_id, allowed, ip_address, reason)
		VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)`,
		log.Timestamp, log.ActorID, log.ActorRole, log.Action,
		log.ResourceType, log.ResourceID, log.Allowed, log.IPAddress, log.Reason,
	)
	if err != nil {
		fmt.Printf("CRITICAL: Failed to write audit log: %v\n", err)
	}
}

// RateLimitMiddleware prevents enumeration attacks
func RateLimitMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if !limiter.Allow() {
			http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
			return
		}
		next.ServeHTTP(w, r)
	})
}

// AuthMiddleware validates JWT and loads user context
func AuthMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		authUser, err := validateJWTAndLoadUser(r)
		if err != nil {
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}
		ctx := context.WithValue(r.Context(), authUserKey, authUser)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

// PRODUCTION HANDLER with full RBAC
func getAccountHandler(w http.ResponseWriter, r *http.Request) {
	authUser, ok := r.Context().Value(authUserKey).(*AuthenticatedUser)
	if !ok || authUser == nil {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	vars := mux.Vars(r)
	requestedID, err := strconv.Atoi(vars["id"])
	if err != nil {
		http.Error(w, "Invalid ID format", http.StatusBadRequest)
		return
	}

	authService := &AuthorizationService{db: db}

	// Check authorization with detailed reason
	allowed, reason := authService.CanAccessAccount(authUser, requestedID)

	// Audit log EVERY access attempt (success and failure)
	logAuditEvent(AuditLog{
		Timestamp:    time.Now().UTC(),
		ActorID:      authUser.ID,
		ActorRole:    authUser.Role,
		Action:       "VIEW_ACCOUNT",
		ResourceType: "account",
		ResourceID:   requestedID,
		Allowed:      allowed,
		IPAddress:    r.RemoteAddr,
		Reason:       reason,
	})

	if !allowed {
		// Return 404 to prevent enumeration (don't reveal if account exists)
		http.Error(w, "Not Found", http.StatusNotFound)
		return
	}

	var user User
	err = db.QueryRow(`
		SELECT id, email, full_name, ssn, balance, region_id 
		FROM users WHERE id = $1`,
		requestedID,
	).Scan(&user.ID, &user.Email, &user.FullName, &user.SSN, &user.Balance, &user.RegionID)

	if err == sql.ErrNoRows {
		http.Error(w, "Not Found", http.StatusNotFound)
		return
	} else if err != nil {
		log.Printf("Database error: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Apply data masking based on role
	isSelfAccess := authUser.ID == requestedID
	authService.MaskSensitiveData(&user, authUser.Role, isSelfAccess)

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("Cache-Control", "no-store, private")
	json.NewEncoder(w).Encode(user)
}

